def _first_balanced_json(text):
    """Return the first balanced {...} or [...] span."""
    start = None
    for i, ch in enumerate(text):
        if ch in "{[":
            start = i
            break
    if start is None:
        return None
    open_ch = text[start]
    close_ch = "}" if open_ch == "{" else "]"
    depth = 0
    in_str = False
    escaped = False
    for i in range(start, len(text)):
        ch = text[i]
        if in_str:
            if escaped:
                escaped = False
            elif ch == "\\":
                escaped = True
            elif ch == '"':
                in_str = False
            continue
        if ch == '"':
            in_str = True
        elif ch == open_ch:
            depth += 1
        elif ch == close_ch:
            depth -= 1
            if depth == 0:
                return text[start:i + 1]
    return None

def _extract_json_with_fallback(text):
    """Full extract_json flow with fallback."""
    candidate = text.strip()
    # Strip a ```json ... ``` fence if present.
    if candidate.startswith("```"):
        inner = candidate[3:]
        if inner[:4].lower() == "json":  # BUG: Matches json5, jsonl, etc.
            inner = inner[4:]
        candidate = inner.rsplit("```", 1)[0].strip()

    print(f"After fence stripping: candidate = {candidate!r}")

    try:
        result = json.loads(candidate)
        print(f"Direct json.loads succeeded")
        return result
    except json.JSONDecodeError as e:
        print(f"Direct json.loads failed: {e}")
        pass

    print(f"Falling back to balanced extractor...")
    span = _first_balanced_json(candidate)
    if span is not None:
        print(f"Balanced extractor found: {span!r}")
        try:
            return json.loads(span)
        except json.JSONDecodeError as exc:
            raise Exception(f"Reply was not valid JSON: {text[:200]!r}") from exc
    raise Exception(f"No JSON value found in reply: {text[:200]!r}")

# Test all variants
test_cases = [
    ('```json\n{"a": 1}\n```', "plain json"),
    ('```json5\n{"a": 1}\n```', "json5"),
    ('```jsonl\n{"a": 1}\n```', "jsonl"),
    ('```jsonschema\n{"a": 1}\n```', "jsonschema"),
]

for test_input, name in test_cases:
    print(f"\n{'='*60}")
    print(f"Test: {name}")
